sql.where:
s.user_id = #{userId}

    and s.problem_id = #{problemId}


    and s.judge_status = #{judgeStatus}


    and lower(s.language) = lower(#{language})


    and s.submitted_at >= #{submittedFrom}


    and s.submitted_at <= #{submittedTo}

mapper.select:
select count(1)
from submissions
where user_id = #{userId}
  and problem_id = #{problemId}

select id as submissionId,
       language,
       judge_status as judgeStatus,
       code_content as codeContent,
       submitted_at as submittedAt
from submissions
where user_id = #{userId}
  and problem_id = #{problemId}
order by submitted_at desc, id desc
limit #{size} offset #{offset}
